import os, re; init='database/models/__init__.py'; existing=open(init).read(); classes=[(f, re.search(r'class\s+(\w+)\s*\(', open(os.path.join('database/models',f)).read()).group(1)) for f in os.listdir('database/models') if f.endswith('.py') and f not in ['__init__.py','main_window.py'] and re.search(r'class\s+(\w+)\s*\(', open(os.path.join('database/models',f)).read())]; [exec(f"existing='from .{f[:-3]} import {cls}\\n'+existing") for f,cls in classes if f'from .{f[:-3]} import {cls}\\n' not in existing]; open(init,'w').write(existing); print('OK')